INSERT INTO `notices` VALUES (1,'🕌 PARKING NOTICE','To help you with your test, here are three variations of a parking notice. These are designed to be clear, professional, and respectful of the Mosque\'s environment.\r\n\r\nOption 1: The \"Polite Reminder\" (Internal Use)\r\nBest for: Mosque gates or the main entrance.\r\n\r\n🕌 PARKING NOTICE\r\nRespect Our Neighbors & Our Community\r\nPlease ensure you are parked within the designated white lines.\r\n\r\nNO DOUBLE PARKING\r\n\r\nNO BLOCKING DRIVEWAYS\r\n\r\nNO PARKING ON YELLOW LINES\r\n\r\nImproper parking causes distress to our neighbors and may result in your vehicle being reported or towed. Please arrive early to find a suitable space.\r\n\r\n\"The best of people are those who are most beneficial to people.\"\r\n— Prophet Muhammad ﷺ','Respect Our Neighbors & Our Community','general',1,0,1,'2026-04-19 13:21:00','2026-05-30 13:21:00',NULL,3,'2026-04-20 13:22:23','2026-04-20 14:45:16');
/*!40000 ALTER TABLE `notices` ENABLE KEYS */;
UNLOCK TABLES;

