INSERT INTO `page_blocks` VALUES (1,1,'hero',1,'{\"heading\": \"Page Title\", \"button_url\": \"/donate\", \"subheading\": \"sub heading\", \"button_text\": \"button text\", \"bg_image_path\": \"pages/6i9ynwibBr8EMtZMSBbFyRDwa1CrMf5dfkqO38oj.jpg\"}','2026-01-01 12:49:36','2026-01-01 12:50:47');
INSERT INTO `page_blocks` VALUES (2,1,'rich_text',2,'{\"html\": \"<p><strong>Blessed Month of Ramadan</strong></p>\\r\\n<p><em>The Prophet ﷺ said:</em></p>\\r\\n<p>&lt;blockquote&gt;<br>&nbsp; &ldquo;Whoever does not give up forged speech and evil actions, Allah (SWT) is not in need of his leaving his food and drink.&rdquo;<br>&nbsp; &lt;br&gt;<br>&nbsp; &lt;em&gt;&mdash; Al-Bukhari&lt;/em&gt;<br>&lt;/blockquote&gt;</p>\\r\\n<p><img src=\\\"data:image/jpeg;base64,\\\" width=\\\"2412\\\" height=\\\"4214\\\"></p>\\r\\n<p>&lt;blockquote&gt;<br>&nbsp; &ldquo;O you who believe! Fasting is prescribed for you as it was prescribed for those before you, that you may attain Taqwa.&rdquo;<br>&nbsp; &lt;br&gt;<br>&nbsp; &lt;em&gt;&mdash; Al-Qur&rsquo;an 2:183&lt;/em&gt;<br>&lt;/blockquote&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;🕌 Tarawih Prayer&lt;/h2&gt;</p>\\r\\n<p>&lt;h3&gt;Merits of Performing Night Prayer (Tarawih)&lt;/h3&gt;</p>\\r\\n<p>&lt;p&gt;<br>The Prophet ﷺ has regarded the Tarawih prayer as a means of forgiveness of sins. He ﷺ said:<br>&lt;/p&gt;</p>\\r\\n<p>&lt;blockquote&gt;<br>&nbsp; &ldquo;Whoever observes the Tarawih prayer at night during Ramadan with complete faith and devotion, only for the sake of the reward in the Hereafter, will have all his previous sins forgiven by Allah (SWT).&rdquo;<br>&lt;/blockquote&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;🌙 Ramadan 2025&lt;/h2&gt;</p>\\r\\n<p>&lt;p&gt;<br>You can download the Ramadan timetable or view it online using the link below.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;<br>&lt;a href=\\\"/downloads/ramadan-timetable-2025.pdf\\\" target=\\\"_blank\\\"&gt;<br>&nbsp; 📥 Download Ramadan Timetable 2025<br>&lt;/a&gt;<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;<br>Or click on the image below to view the timetable.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;&lt;em&gt;<br>Please note: All dates and times are subject to the Masjid being open.<br>Please check the website for the latest updates.<br>&lt;/em&gt;&lt;/p&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;🕋 Isha &amp; Tarawih&lt;/h2&gt;</p>\\r\\n<p>&lt;p&gt;<br>Please see the Ramadan calendar for updated Isha and Tarawih times.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;🕌 Eid Jamaat Times&lt;/h2&gt;</p>\\r\\n<p>&lt;ul&gt;<br>&nbsp; &lt;li&gt;&lt;strong&gt;1st Jamaat:&lt;/strong&gt; 8:00 AM&lt;/li&gt;<br>&nbsp; &lt;li&gt;&lt;strong&gt;2nd Jamaat:&lt;/strong&gt; 9:00 AM&lt;/li&gt;<br>&nbsp; &lt;li&gt;&lt;strong&gt;3rd Jamaat:&lt;/strong&gt; 10:30 AM&lt;/li&gt;<br>&lt;/ul&gt;</p>\\r\\n<p>&lt;p&gt;<br>&lt;em&gt;* All Islamic dates and festivals are subject to the sighting of the moon.&lt;/em&gt;<br>&lt;/p&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;📖 What is the Month of Ramadan?&lt;/h2&gt;</p>\\r\\n<p>&lt;p&gt;<br>The month of Ramadan is the ninth month of the Islamic calendar. It is observed by Muslims all over the world as a month of fasting (Sawm).<br>It lasts for 29 or 30 days, depending on the sighting of the moon.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;<br>The Prophet Muhammad ﷺ said:<br>&lt;/p&gt;</p>\\r\\n<p>&lt;blockquote&gt;<br>&nbsp; &ldquo;It is Allah&rsquo;s own month. It is the chief of all months and the most glorious one.&rdquo;<br>&lt;/blockquote&gt;</p>\\r\\n<p>&lt;p&gt;<br>Fasting during Ramadan is one of the five pillars of Islam and is obligatory upon every adult Muslim.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;🌴 Breaking the Fast with Dates&lt;/h2&gt;</p>\\r\\n<p>&lt;p&gt;<br>During Ramadan, Muslims fast from before sunrise until sunset. It is Sunnah to break the fast with dates.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;blockquote&gt;<br>&nbsp; &ldquo;When one of you is fasting, he should break his fast with dates; if he cannot get any, then with water, for it is pure.&rdquo;<br>&nbsp; &lt;br&gt;<br>&nbsp; &lt;em&gt;&mdash; Hadith&lt;/em&gt;<br>&lt;/blockquote&gt;</p>\\r\\n<p>&lt;p&gt;<br>Dates are rich in natural sugars and nutrients, helping to restore energy after a long day of fasting.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;🕊️ Sunnah of Fasting&lt;/h2&gt;</p>\\r\\n<p>&lt;ol&gt;<br>&nbsp; &lt;li&gt;Taking the pre-dawn meal (Suhoor).&lt;/li&gt;<br>&nbsp; &lt;li&gt;Delaying Suhoor.&lt;/li&gt;<br>&nbsp; &lt;li&gt;Hastening to break the fast at sunset.&lt;/li&gt;<br>&nbsp; &lt;li&gt;Breaking the fast before Maghrib prayer.&lt;/li&gt;<br>&nbsp; &lt;li&gt;Making Dua at the time of Iftar.&lt;/li&gt;<br>&nbsp; &lt;li&gt;Refraining from bad speech and actions.&lt;/li&gt;<br>&nbsp; &lt;li&gt;Being generous and reciting the Qur&rsquo;an.&lt;/li&gt;<br>&nbsp; &lt;li&gt;Increasing worship during the last 10 nights.&lt;/li&gt;<br>&lt;/ol&gt;</p>\\r\\n<p>&lt;hr&gt;</p>\\r\\n<p>&lt;h2&gt;💰 Zakat-ul-Fitr&lt;/h2&gt;</p>\\r\\n<p>&lt;p&gt;<br>Before the Eid al-Fitr prayer, every adult Muslim who possesses food in excess of their needs must pay Zakat-ul-Fitr (Fitrana).<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;<br>The head of the household may also pay on behalf of dependants such as children or relatives.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;<br>Zakat-ul-Fitr should be paid before Eid prayer so that the poor can also enjoy the day of Eid.<br>&lt;/p&gt;</p>\\r\\n<p>&lt;p&gt;<br>&lt;strong&gt;Amount for this year:&lt;/strong&gt; &pound;5.00 per person<br>&lt;/p&gt;</p>\\r\\n<p>tent</p>\", \"title\": \"ramadan special\"}','2026-01-01 12:51:01','2026-01-02 18:30:06');
