CREATE TABLE `ramadan_daily_times` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `ramadan_year_id` bigint unsigned NOT NULL,
  `day` int NOT NULL,
  `date` date NOT NULL,
  `hijri_date` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sehr_end` time DEFAULT NULL,
  `fajr` time DEFAULT NULL,
  `sunrise` time DEFAULT NULL,
  `dhuhr` time DEFAULT NULL,
  `asr` time DEFAULT NULL,
  `maghrib` time DEFAULT NULL,
  `isha` time DEFAULT NULL,
  `tahajjud` time DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ramadan_daily_times_ramadan_year_id_foreign` (`ramadan_year_id`),
  CONSTRAINT `ramadan_daily_times_ramadan_year_id_foreign` FOREIGN KEY (`ramadan_year_id`) REFERENCES `ramadan_settings` (`id`) ON DELETE CASCADE
